div.style:
position: absolute;
top: 200px;
left: 0px;
width: 100%;
text-align: center;
z-index: 9999;
pointer-events: none;

span.t-attf-style:
display: inline-block;
font-size: 120px;
font-weight: 900;
font-family: Arial, Helvetica, sans-serif;
letter-spacing: 6px;
text-transform: uppercase;
transform: rotate(-45deg);
white-space: nowrap;
opacity: 0.12;
color: #{'#00aa44' if o.payment_watermark == 'cash' else '#0044cc'};
border: 8px solid #{'#00aa44' if o.payment_watermark == 'cash' else '#0044cc'};
padding: 12px 36px;
border-radius: 10px;

div.style:
position: fixed;
top: 0;
left: 0;
width: 100%;
height: 100%;
display: flex;
align-items: center;
justify-content: center;
pointer-events: none;
z-index: 9999;

span.t-attf-style:
display: inline-block;
font-size: 120px;
font-weight: 900;
font-family: Arial, Helvetica, sans-serif;
letter-spacing: 6px;
text-transform: uppercase;
transform: rotate(-45deg);
white-space: nowrap;
opacity: 0.12;
color: #{'#00aa44' if o.payment_watermark == 'cash' else '#0044cc'};
border: 8px solid #{'#00aa44' if o.payment_watermark == 'cash' else '#0044cc'};
padding: 12px 36px;
border-radius: 10px;
